INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('SCI_ES2c_L3_B', 'SCI_ES2c', 3, 'B', 'Discern (Anomaly Detection)', NULL, '5 different rocks from outside', 'pebbles, stones from road', 'Risk_Level_A', 'Do not throw rocks.', 'Variation B: "Amara tried to do an experiment on Rocks & Minerals but it failed. Why did she fail physically?"', 'Child identifies the mechanical error and explains how Rocks & Minerals really works.', 'Child agrees with the flawed reasoning. Parent prompts them to think about physical variables.', 'What was the mechanical error?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden","savanna","wetland","shamba"],"food":["matooke","mangoes","chapati","jackfruit"]}}', 0);
