INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('SCI_ES2e_L3_A', 'SCI_ES2e', 3, 'A', 'Discern (Anomaly Detection)', NULL, 'notebook, pencil, view of the sky', 'chalk on wall', 'Risk_Level_A', 'Safe for independent work.', 'Variation A: "Show me how Weather Tracking works physically. If I do [X], what should happen according to the rules of science?"', 'Child identifies the mechanical error and explains how Weather Tracking really works.', 'Child agrees with the flawed reasoning. Parent prompts them to think about physical variables.', 'What was the mechanical error?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden","savanna","wetland","shamba"],"food":["matooke","mangoes","chapati","jackfruit"]}}', 0);
