INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('SCI_ES2j_L4_M', 'SCI_ES2j', 4, 'M', 'Milestone (Real-World Application)', NULL, 'water from tap/jerrycan, cup, soil patch', 'bucket of water', 'Risk_Level_B', 'Do not waste essential household drinking water.', 'Milestone: Present the child with an unlabeled real-world problem involving the garden or weather (Natural Resources & Stewardship). "We have a problem with our crops / yard. Show me how to fix or prepare for it."', 'Child independently applies Natural Resources & Stewardship to solve the real-world problem.', 'Child cannot transfer knowledge to the unlabeled problem.', 'Explain your model and stewardship choice.', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden","savanna","wetland","shamba"],"food":["matooke","mangoes","chapati","jackfruit"]}}', 0);